    const hts  = turn.htsRate;

    // MFN comes only from the authoritative USITC schedule. We previously
    // fell back to the model's suggested_duty_pct when the lookup missed,
    // but the model returned values like 0.039 (decimal fractions) which
    // produced "0.039%" in the cell. The model is unreliable for numbers —
    // when the schedule misses, leave MFN blank and let the user enter it.
    const compound = turn.parsedCompound;

    let mfn = 0;
    let mfnLabel = '';
    let dollarPatch: string | null = null;

    if (hts?.found && hts.rate != null) {
      // Pure ad-valorem rate from USITC schedule
      mfn = hts.rate;
      const via = hts.matchType === 'exact'  ? ''
                : hts.matchType === 'prefix8' ? ` (via 8-digit parent ${hts.hts})`
                : hts.matchType === 'prefix6' ? ` (via 6-digit parent ${hts.hts})`
                : hts.matchType === 'prefix4' ? ` (via 4-digit heading ${hts.hts} — all subheadings share this rate)`
                : '';
      mfnLabel = `${mfn}% MFN${via}`;
    } else if (hts?.matchType === 'prefix4-ambiguous') {
      mfnLabel = `MFN: heading ${hts.hts} has subheadings with different rates — enter manually`;
    } else if (hts?.found && hts.rate === null && compound && compound.percent !== null) {
      // Compound rate: we extracted the % part (e.g. "3.4% + $0.25/pc" → 3.4%)
      mfn = compound.percent;
      mfnLabel = `${mfn}% MFN (from compound rate: ${hts.rateText})`;
      if (compound.dollarPerPiece != null) {
        dollarPatch = String(compound.dollarPerPiece);
        mfnLabel += ` + $${compound.dollarPerPiece}/pc (applied to $ field)`;
      } else if (compound.hasNonPieceSpecific) {
        mfnLabel += ` — non-per-piece specific duty (${hts.rateText}) not auto-filled, enter in $ field manually`;
      }
    } else if (hts?.found && hts.rateText) {
      mfnLabel = `MFN: ${hts.rateText} (non-ad-valorem — enter the equivalent percent manually)`;
    } else {
      mfnLabel = 'MFN: not in bundled USITC schedule — verify the HTS code and enter the rate manually';
    }

    const s301Rate  = s301?.found && s301.rate != null ? s301.rate : 0;
    const trumpRate = this.trump2025Result?.found && this.trump2025Result.rate != null
                      ? this.trump2025Result.rate
                      : (parseFloat(this.form.value.trump2025Rate) || 0);

    const patch: Record<string, string> = {
      mfnRate:        String(mfn),
      section301Rate: String(s301Rate),
      trump2025Rate:  String(trumpRate),
    };
    if (dollarPatch !== null) patch['dollarAmount'] = dollarPatch;
    this.form.patchValue(patch);

    const total     = mfn + s301Rate + trumpRate;
    const s301Part  = s301?.found ? ` + ${s301Rate}% Section 301 (${s301.list})` : '';
    const trumpPart = trumpRate ? ` + ${trumpRate}% Trump 2025 (${this.trump2025Result?.country ?? this.fobCountry ?? '?'})` : '';

    this._snakcbar.open(
      `Applied ${mfnLabel}${s301Part}${trumpPart} = ${total}% total`,
      'close',
      { duration: 8000 },
    );
  }

  confidenceClass(c: HtsClassification['confidence']): string {
    return { high: 'conf-high', medium: 'conf-medium', low: 'conf-low' }[c] ?? '';
  }

  private scrollChatToBottom() {
    setTimeout(() => {
      this.chatBottom?.nativeElement?.scrollIntoView({ behavior: 'smooth' });
    }, 50);
  }
