  prompt_cache_hit_tokens?: number;
  /** Tokens processed at the normal input-token rate. */
  prompt_cache_miss_tokens?: number;
  /** Tokens written to an explicit cache block (Qwen/Anthropic-style caches). */
  prompt_cache_creation_tokens?: number;
  /** Hit tokens divided by total prompt/input tokens, 0-1. */
  prompt_cache_hit_rate?: number;
  /** Hit tokens divided by total prompt/input tokens, 0-100. */
  prompt_cache_hit_rate_pct?: number;
  /** False when the provider returned tokens but no cache-specific telemetry. */
