/** Shape returned by POST /api/openrouter/chat (proxied OpenAI / DeepSeek response). */
interface ChatApiResponse {
  choices?: Array<{
    message?: {
      content?: string;
      /** DeepSeek native chain-of-thought field. */
      reasoning_content?: string;
      /** OpenRouter sometimes flattens DeepSeek's reasoning into `reasoning`. */
      reasoning?: string;
    };
  }>;
  usage?: ChatUsage;
}

// ── Service ───────────────────────────────────────────────────────────────────

@Injectable({ providedIn: 'root' })
export class HtsClassifierService {
  private base = environment.url;

  constructor(private http: HttpClient) {}

  /**
   * Build the full initial message array for the first AI call.
   * The system prompt goes first (cache-friendly); variable content last.
   *
   * @param knownContext  Optional key→value facts already known from the row
   *   (e.g. { 'Country of origin': 'China', 'FOB country': 'China' }).
   *   Injected into the initial user message so the model skips questions about
   *   things we already know.
   */
  buildInitialMessages(
    cleanedDesc: string,
    crossResults: CrossRuling[],
    knownContext: Record<string, string> = {},
  ): ChatMessage[] {
    const crossSummary = crossResults.length
      ? crossResults.map(r =>
          `• Ruling ${r.rulingNumber} (${r.rulingDate}): ${r.subject}` +
          (r.tariffs?.length ? ` — HTS: ${r.tariffs.join(', ')}` : '')
        ).join('\n')
      : null;

    const contextEntries = Object.entries(knownContext).filter(([, v]) => v?.trim());
    const contextBlock = contextEntries.length
      ? `Known context (do NOT ask about any of these — they are already confirmed):\n` +
        contextEntries.map(([k, v]) => `• ${k}: ${v}`).join('\n') + '\n\n'
      : '';

    // CROSS block leads the message — it is the primary classification authority.
    // If no rulings were found, tell the model explicitly so it doesn't invent any.
    const crossBlock = crossSummary
      ? `CBP CROSS rulings (your PRIMARY classification authority — check these before\n` +
        `any heading-text analysis; if a ruling matches, cite it and classify accordingly):\n` +
        crossSummary + '\n\n'
      : `CBP CROSS rulings: none found for this product description. ` +
        `Proceed with heading-text analysis and GRI reasoning.\n\n`;

    return [
      { role: 'system', content: SYSTEM_PROMPT },
      {
        role: 'user',
        content:
          crossBlock +
          `Product description (cleaned, ready for classification):\n${cleanedDesc}\n\n` +
          contextBlock +
          `Please classify this product. ` +
          `Start by evaluating the CROSS rulings above. ` +
          `If a ruling clearly matches, cite it and output the classification JSON. ` +
          `If no ruling settles it, apply heading-text analysis and ask a clarifying question if needed.`,
      },
    ];
  }

  /**
   * Send a chat request via the backend proxy.
   * Returns the raw content string from the model's first choice.
   *
   * When reasoningEffort is provided and not 'none', it is sent as
   * reasoning_effort in the request body. The backend routes DeepSeek models
   * to DeepSeek's API directly (where reasoning_effort is natively supported
   * by deepseek-reasoner) and other models to OpenRouter.
   */
  chat(
    model: string,
    messages: ChatMessage[],
    reasoningEffort?: string,
    api?: AiApiBackend,
    sessionId?: string,
    telemetryFeature?: string,
  ): Observable<ChatResult> {
    const thinkingActive = !!reasoningEffort && reasoningEffort !== 'none';
    const body: Record<string, unknown> = {
      model,
      messages,
      // Thinking mode (deepseek-v4-pro) consumes 2–5k reasoning tokens before
      // emitting the final JSON. 768 truncated mid-reasoning → empty content.
      max_tokens: thinkingActive ? 8192 : 2048,
      // DeepSeek requires temperature=1.0 when thinking is enabled.
      temperature: thinkingActive ? 1.0 : 0.1,
    };
    if (thinkingActive) {
      body['reasoning_effort'] = reasoningEffort;
    }
    if (api) {
      body['api'] = api;
    }
    if (sessionId) {
      body['session_id'] = sessionId;
    }
    if (telemetryFeature) {
      body['telemetry_feature'] = telemetryFeature;
    }
    return this.http
      .post<ChatApiResponse>(`${this.base}/api/openrouter/chat`, body)
      .pipe(map(res => {
        const msg = res.choices?.[0]?.message;
        return {
          content: msg?.content ?? '',
          reasoningContent: msg?.reasoning_content ?? msg?.reasoning ?? '',
          usage: res.usage ?? null,
        };
      }));
  }

  /**
   * Ask the model to suggest shorter CROSS search terms for a cleaned description
   * that returned no results. The model is better than a naive word-drop strategy
   * because it understands which tokens are classification-relevant — materials
   * ("PVC", "ceramic") and product types ("mat", "figurine") should survive,
   * while qualifiers ("Anti-fatigue", "non-slip") are trimmed first.
   *
   * Always runs without thinking/reasoning — this is a cheap helper call.
   * Returns 1–3 progressively shorter terms, not including the original desc.
   * Returns [] if the call fails or the model returns unparseable output.
   */
  suggestCrossTerms(
    cleanedDesc: string,
    model: string,
    api?: AiApiBackend,
  ): Observable<string[]> {
    const messages: ChatMessage[] = [{
      role: 'user',
      content:
        `I searched CBP CROSS rulings for: "${cleanedDesc}" and got zero results.\n\n` +
        `Suggest 3–5 alternative search terms to try. Each suggestion should use ONE of these strategies:\n` +
        `(a) Remove the least HTS-classification-relevant words first — qualifiers, attributes, ` +
        `adverbs (non-slip, anti-fatigue, decorative, heavy-duty…). Preserve material words ` +
        `(vinyl, ceramic, PVC, iron…) and the core product type.\n` +
        `(b) Substitute alternate spellings or phrasings that CBP rulings commonly use — ` +
        `e.g. hyphenated compounds often appear unhyphenated or space-separated in rulings ` +
        `("anti-fatigue" → "antifatigue" or "anti fatigue"; "non-slip" → "nonslip"; ` +
        `"roll-top" → "rolltop"). Try the most likely CBP variant.\n\n` +
        `Return ONLY a JSON array of strings — no explanation, no markdown.\n` +
        `Example input: "Anti-fatigue PVC Kitchen Mat"\n` +
        `Example output: ["antifatigue PVC Kitchen Mat", "anti fatigue PVC Kitchen Mat", "PVC Kitchen Mat", "Kitchen Mat"]`,
    }];
    return this.chat(model, messages, 'none', api).pipe(
      map(result => {
        const match = result.content.match(/\[[\s\S]*?\]/);
        if (!match) { return []; }
        const parsed = JSON.parse(match[0]);
        if (!Array.isArray(parsed)) { return []; }
        return (parsed as unknown[])
          .filter((t): t is string => typeof t === 'string' && t.trim().length > 0)
          .filter(t => t.trim() !== cleanedDesc.trim())
          .slice(0, 5);
      }),
      catchError(() => of([])),
    );
  }

  /**
   * Parse the model's response text into a structured AiResponse.
   * Handles ```json fenced blocks and bare JSON objects.
   * Falls back to a question response if parsing fails.
   */
  parseResponse(content: string): AiResponse {
    // Try fenced code block first, then bare JSON object
    const fenced = content.match(/```(?:json)?\s*([\s\S]+?)\s*```/);
    const bare   = content.match(/(\{[\s\S]+\})/);
    const raw    = fenced?.[1] ?? bare?.[1];

    if (raw) {
      try {
        const parsed = JSON.parse(raw);
        if (parsed.type === 'classification' || parsed.type === 'question' || parsed.type === 'explanation') {
          return parsed as AiResponse;
        }
      } catch {
        // fall through
      }
    }

    // Return the content as a plain question response
    return { type: 'question', text: content.trim() };
  }
}

