                duration: 5000
              });
            }
          }
        } catch (err) {
          console.error('[Login] send() failed:', err);
        }
      } else {
        this.snackbar.open('The email is not a valid email address.', 'OK', {
          duration: 5000
        });
      }
    } else {
      this.snackbar.open('Please fill all the fields.', 'OK', {
        duration: 5000
      });
    }
  }

  /** Opens the Microsoft login popup and exchanges the Azure ID token for a Designflow JWT. */
  async loginWithMicrosoft(): Promise<void> {
    this.microsoftLoading = true;
    this.cd.markForCheck();
    try {
      const idToken = await this.azureSso.loginPopup();
      const data = await firstValueFrom(this.itemService.loginWithAzure(idToken));
      if (data?.status === 'success') {
        await this._onLoginSuccess(data.token);
      } else {
        this.snackbar.open('Microsoft sign-in failed. Please try again.', 'OK', { duration: 5000 });
